// ====== Policy Forward (Generalized, Policy Only) ======

#include <math.h>

static inline float tanhf_fast(float x) { return tanhf(x); }

static inline void forward_policy(const float input[], float output[]) {
    const float *curr = input;
    static float layer0[64];
    for (int i = 0; i < 64; i++) {
        float s = mlp_extractor_policy_net_0_bias_bias[i];
        for (int j = 0; j < 4; j++) {
            s += mlp_extractor_policy_net_0_weight_weight[i][j] * curr[j];
        }
        layer0[i] = tanhf_fast(s);
    }
    curr = layer0;
    static float layer1[64];
    for (int i = 0; i < 64; i++) {
        float s = mlp_extractor_policy_net_2_bias_bias[i];
        for (int j = 0; j < 64; j++) {
            s += mlp_extractor_policy_net_2_weight_weight[i][j] * curr[j];
        }
        layer1[i] = tanhf_fast(s);
    }
    curr = layer1;
    static float layer2[2];
    for (int i = 0; i < 2; i++) {
        float s = action_net_bias_bias[i];
        for (int j = 0; j < 64; j++) {
            s += action_net_weight_weight[i][j] * curr[j];
        }
        layer2[i] = s;
    }
    curr = layer2;
    for (int i = 0; i < 2; i++) output[i] = curr[i];
}
